// `shared: true` means every user who opens this Artifact reads/writes the
// SAME data — required for tasks/members/accounts so one admin's changes
// (including deletes) are visible to every other admin. `shared: false`
// (the default) is per-browser-session storage, which is only appropriate
// for "which account is logged in on THIS device" (njms_session).
const getFromStorage = async (key, shared = true) => {
  try { const r = await window.storage.get(key, shared); return r ? JSON.parse(r.value) : null; }
  catch { return null; }
};
const setToStorage = async (key, val, shared = true) => {
  try { await window.storage.set(key, JSON.stringify(val), shared); } catch {}
};

// ─── SIMPLE PASSWORD HASH (client-side, not cryptographically secure) ─────────
// This keeps the demo's plain-text password from sitting in storage as-is.
// For a real public deployment, replace with proper server-side auth.
const hashPassword = async (pw) => {
  try {
    const enc = new TextEncoder().encode(pw);
    const buf = await crypto.subtle.digest("SHA-256", enc);
    return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2, "0")).join("");
  } catch {
    // Fallback if crypto.subtle isn't available
    let h = 0;
    for (let i = 0; i < pw.length; i++) { h = (h * 31 + pw.charCodeAt(i)) | 0; }
    return "fallback_" + h;
  }
};

