// Build a wa.me link to send a member an invite. Phone must include country code.
const buildWhatsAppInviteUrl = (member) => {
  const digits = (member.phone || "").replace(/[^\d+]/g, "").replace(/^\+/, "");
  const message =
    `Namaste ${member.name} ji 🙏\n\n` +
    `You're invited to join ${ORG_NAME_EN} (${ORG_NAME}) on the NJMS Community Manager app.\n\n` +
    `Tap here to complete your sign-up:\n${JOIN_URL}\n\n` +
    `Please reply to confirm your participation. Jai Maheshwari!`;
  return `https://wa.me/${digits}?text=${encodeURIComponent(message)}`;
};

// Build a wa.me link to notify a member their self-registration has been
// approved. Opens a pre-filled message in WhatsApp; the admin still taps
// Send themselves (true unattended auto-send needs the WhatsApp Business
// API and a backend, which this Artifact-only app doesn't have).
const buildWhatsAppApprovalUrl = (member) => {
  const digits = (member.phone || "").replace(/[^\d+]/g, "").replace(/^\+/, "");
  const message =
    `Namaste ${member.name} ji 🙏\n\n` +
    `Good news — your registration with ${ORG_NAME_EN} (${ORG_NAME}) has been approved! ✅\n\n` +
    `Welcome to the Sabha. Jai Maheshwari!`;
  return `https://wa.me/${digits}?text=${encodeURIComponent(message)}`;
};


const useViewport = () => {
  const [width, setWidth] = useState(typeof window !== "undefined" ? window.innerWidth : 1024);
  useEffect(() => {
    const onResize = () => setWidth(window.innerWidth);
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);
  return {
    width,
    isMobile: width < 720,
    isTablet: width >= 720 && width < 1024,
  };
};

