// Modal
const Modal = ({ open, onClose, title, children, width = 560 }) => {
  const { isMobile } = useViewport();
  if (!open) return null;
  return (
    <div style={{
      position: "fixed", inset: 0, background: "rgba(15,10,5,0.65)",
      zIndex: 1000, display: "flex", alignItems: isMobile ? "flex-end" : "center",
      justifyContent: "center", padding: isMobile ? 0 : 16, backdropFilter: "blur(3px)"
    }} onClick={onClose}>
      <div style={{
        background: "#ffffff", border: "1px solid #d9c195",
        borderRadius: isMobile ? "18px 18px 0 0" : 16,
        width: "100%", maxWidth: isMobile ? "100%" : width,
        maxHeight: isMobile ? "92vh" : "90vh",
        overflow: "auto", boxShadow: "0 24px 64px rgba(90,15,15,0.35)"
      }} onClick={e => e.stopPropagation()}>
        <div style={{
          display: "flex", alignItems: "center", justifyContent: "space-between",
          padding: isMobile ? "16px 18px 14px" : "20px 24px 16px", borderBottom: "1px solid #d9c195",
          position: "sticky", top: 0, background: "#ffffff", zIndex: 1
        }}>
          <h3 style={{ margin: 0, color: "#8a1414", fontSize: 17, fontWeight: 700 }}>{title}</h3>
          <button onClick={onClose} style={{
            background: "none", border: "none", color: "#7a5a3a",
            fontSize: 24, cursor: "pointer", lineHeight: 1, padding: "4px 6px"
          }}>×</button>
        </div>
        <div style={{ padding: isMobile ? "16px 18px 22px" : "20px 24px 24px" }}>{children}</div>
      </div>
    </div>
  );
};

// Confirm Dialog — replaces window.confirm(), which is blocked inside this
// app's sandboxed environment and silently does nothing when called.
const ConfirmDialog = ({ open, title = "Are you sure?", message, confirmLabel = "Delete", onConfirm, onCancel }) => {
  if (!open) return null;
  return (
    <Modal open={open} onClose={onCancel} title={title} width={380}>
      <p style={{ margin: "0 0 20px", color: "#3a1010", fontSize: 14, lineHeight: 1.5 }}>{message}</p>
      <div style={{ display: "flex", gap: 10, justifyContent: "flex-end" }}>
        <button onClick={onCancel} style={{
          padding: "10px 18px", background: "transparent",
          border: "1px solid #d9c195", borderRadius: 8,
          color: "#7a5a3a", cursor: "pointer", fontSize: 14
        }}>Cancel</button>
        <button onClick={onConfirm} style={{
          padding: "10px 18px", background: "#ef4444",
          border: "none", borderRadius: 8, color: "#fff",
          fontWeight: 700, cursor: "pointer", fontSize: 14
        }}>{confirmLabel}</button>
      </div>
    </Modal>
  );
};


