// ─── TASK FORM ────────────────────────────────────────────────────────────────
const TaskForm = ({ initial, onSave, onClose }) => {
  const { isMobile } = useViewport();
  const [form, setForm] = useState({
    title: "", category: ACTIVITY_CATEGORIES[0], date: today(),
    status: "Pending", priority: "Medium", notes: "", duration: 1,
    ...initial
  });
  const set = (k, v) => setForm(p => ({ ...p, [k]: v }));

  return (
    <div>
      <Field label="Activity Title">
        <input style={inputStyle} value={form.title}
          onChange={e => set("title", e.target.value)} placeholder="What did you do?" />
      </Field>
      <div style={{ display: "grid", gridTemplateColumns: isMobile ? "1fr" : "1fr 1fr", gap: 12 }}>
        <Field label="Category">
          <select style={inputStyle} value={form.category} onChange={e => set("category", e.target.value)}>
            {ACTIVITY_CATEGORIES.map(c => <option key={c}>{c}</option>)}
          </select>
        </Field>
        <Field label="Date">
          <input type="date" style={inputStyle} value={form.date}
            onChange={e => set("date", e.target.value)} />
        </Field>
        <Field label="Status">
          <select style={inputStyle} value={form.status} onChange={e => set("status", e.target.value)}>
            {STATUS_OPTIONS.map(s => <option key={s}>{s}</option>)}
          </select>
        </Field>
        <Field label="Priority">
          <select style={inputStyle} value={form.priority} onChange={e => set("priority", e.target.value)}>
            {PRIORITY.map(p => <option key={p}>{p}</option>)}
          </select>
        </Field>
      </div>
      <Field label="Duration (hours)">
        <input type="number" min="0.5" max="24" step="0.5" style={inputStyle}
          value={form.duration} onChange={e => set("duration", parseFloat(e.target.value) || 1)} />
      </Field>
      <Field label="Notes / Description">
        <textarea style={{ ...inputStyle, minHeight: 80, resize: "vertical" }}
          value={form.notes} onChange={e => set("notes", e.target.value)}
          placeholder="Add details about this activity..." />
      </Field>
      <div style={{ display: "flex", gap: 10, justifyContent: "flex-end", marginTop: 8, flexDirection: isMobile ? "column-reverse" : "row" }}>
        <button onClick={onClose} style={{
          padding: "12px 20px", background: "transparent",
          border: "1px solid #d9c195", borderRadius: 8,
          color: "#7a5a3a", cursor: "pointer", fontSize: 14, width: isMobile ? "100%" : "auto"
        }}>Cancel</button>
        <button onClick={() => {
          if (!form.title.trim()) return alert("Please enter an activity title.");
          onSave({ ...form, id: form.id || `t${Date.now()}` });
        }} style={{
          padding: "12px 24px", background: "linear-gradient(135deg, #c8960c, #e6b020)",
          border: "none", borderRadius: 8, color: "#1a0e02",
          fontWeight: 700, cursor: "pointer", fontSize: 14, width: isMobile ? "100%" : "auto"
        }}>Save Activity</button>
      </div>
    </div>
  );
};

