// ─── CALENDAR VIEW ────────────────────────────────────────────────────────────
const CalendarView = ({ tasks, onAddTask, onDelete }) => {
  const { isMobile } = useViewport();
  const now = new Date();
  const [year, setYear] = useState(now.getFullYear());
  const [month, setMonth] = useState(now.getMonth());
  const [selectedDate, setSelectedDate] = useState(null);
  const [showAddModal, setShowAddModal] = useState(false);
  const [editTask, setEditTask] = useState(null);

  const days = daysInMonth(year, month);
  const firstDay = firstDayOf(year, month);
  const todayStr = today();

  const tasksByDate = {};
  tasks.forEach(t => {
    if (!tasksByDate[t.date]) tasksByDate[t.date] = [];
    tasksByDate[t.date].push(t);
  });

  const selectedTasks = selectedDate ? (tasksByDate[selectedDate] || []) : [];

  const prevMonth = () => { if (month === 0) { setYear(y => y - 1); setMonth(11); } else setMonth(m => m - 1); };
  const nextMonth = () => { if (month === 11) { setYear(y => y + 1); setMonth(0); } else setMonth(m => m + 1); };

  const dayLabels = isMobile ? ["S", "M", "T", "W", "T", "F", "S"] : ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
  const cellHeight = isMobile ? 44 : 72;

  return (
    <div>
      {/* Calendar Header */}
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 20, flexWrap: "wrap", gap: 10 }}>
        <h2 style={{ margin: 0, color: "#8a1414", fontSize: isMobile ? 17 : 20 }}>📅 Activity Calendar</h2>
        <button onClick={() => { setSelectedDate(today()); setEditTask(null); setShowAddModal(true); }} style={{
          padding: "10px 18px", background: "linear-gradient(135deg, #c8960c, #e6b020)",
          border: "none", borderRadius: 8, color: "#1a0e02",
          fontWeight: 700, cursor: "pointer", fontSize: 13
        }}>+ Log Activity</button>
      </div>

      <div style={{ background: "#ffffff", border: "1px solid #f3e6c9", borderRadius: 16, overflow: "hidden" }}>
        {/* Month Nav */}
        <div style={{
          display: "flex", alignItems: "center", justifyContent: "space-between",
          padding: "14px 16px", borderBottom: "1px solid #f3e6c9",
          background: "linear-gradient(135deg, #f3e6c9, #ffffff)"
        }}>
          <button onClick={prevMonth} style={{ background: "none", border: "1px solid #d9c195", borderRadius: 8, color: "#c8960c", cursor: "pointer", padding: "6px 14px", fontSize: 16 }}>‹</button>
          <span style={{ color: "#8a1414", fontWeight: 700, fontSize: isMobile ? 15 : 18 }}>{fmtMonth(year, month)}</span>
          <button onClick={nextMonth} style={{ background: "none", border: "1px solid #d9c195", borderRadius: 8, color: "#c8960c", cursor: "pointer", padding: "6px 14px", fontSize: 16 }}>›</button>
        </div>

        {/* Day Headers */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", borderBottom: "1px solid #f3e6c9" }}>
          {dayLabels.map((d, i) => (
            <div key={i} style={{ textAlign: "center", padding: "8px 0", color: "#7a5a3a", fontSize: 11, fontWeight: 600 }}>{d}</div>
          ))}
        </div>

        {/* Calendar Grid */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)" }}>
          {Array(firstDay).fill(null).map((_, i) => (
            <div key={`e${i}`} style={{ minHeight: cellHeight, borderRight: "1px solid #f0e2c4", borderBottom: "1px solid #f0e2c4" }} />
          ))}
          {Array(days).fill(null).map((_, i) => {
            const d = i + 1;
            const ds = dateStr(year, month, d);
            const dt = tasksByDate[ds] || [];
            const isToday = ds === todayStr;
            const isSelected = ds === selectedDate;
            return (
              <div key={d} onClick={() => setSelectedDate(ds === selectedDate ? null : ds)} style={{
                minHeight: cellHeight, padding: isMobile ? "4px 3px" : "6px 8px", cursor: "pointer",
                borderRight: "1px solid #f0e2c4", borderBottom: "1px solid #f0e2c4",
                background: isSelected ? "#f3e0b3cc" : isToday ? "#fbf3e699" : "transparent",
                transition: "background 0.15s",
                position: "relative"
              }}
                onMouseEnter={e => { if (!isSelected) e.currentTarget.style.background = "#fbf3e655"; }}
                onMouseLeave={e => { if (!isSelected) e.currentTarget.style.background = isToday ? "#fbf3e699" : "transparent"; }}>
                <div style={{
                  width: isMobile ? 20 : 26, height: isMobile ? 20 : 26, borderRadius: "50%", display: "flex",
                  alignItems: "center", justifyContent: "center",
                  background: isToday ? "#c8960c" : "transparent",
                  color: isToday ? "#1a0e02" : isSelected ? "#8a1414" : "#8a6a48",
                  fontWeight: isToday || isSelected ? 700 : 400, fontSize: isMobile ? 11 : 13, marginBottom: 3,
                  margin: isMobile ? "0 auto 3px" : "0 0 4px"
                }}>{d}</div>
                {isMobile ? (
                  dt.length > 0 && (
                    <div style={{ display: "flex", justifyContent: "center", gap: 2 }}>
                      {dt.slice(0, 3).map((t, idx) => (
                        <div key={idx} style={{ width: 5, height: 5, borderRadius: "50%", background: statusColor(t.status) }} />
                      ))}
                    </div>
                  )
                ) : (
                  <>
                    {dt.slice(0, 3).map((t, idx) => (
                      <div key={idx} style={{
                        fontSize: 10, padding: "1px 5px", borderRadius: 4,
                        background: statusColor(t.status) + "33",
                        color: statusColor(t.status),
                        marginBottom: 2, overflow: "hidden", whiteSpace: "nowrap", textOverflow: "ellipsis"
                      }}>{t.title}</div>
                    ))}
                    {dt.length > 3 && <div style={{ fontSize: 10, color: "#7a5a3a" }}>+{dt.length - 3} more</div>}
                  </>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* Selected Day Detail */}
      {selectedDate && (
        <div style={{ marginTop: 20 }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 12, flexWrap: "wrap", gap: 8 }}>
            <h3 style={{ margin: 0, color: "#3a1010", fontSize: 15 }}>
              {fmt(selectedDate)} <span style={{ color: "#7a5a3a", fontWeight: 400 }}>({selectedTasks.length})</span>
            </h3>
            <button onClick={() => { setEditTask(null); setShowAddModal(true); }} style={{
              padding: "7px 14px", background: "#f3e6c9", border: "1px solid #c8960c55",
              borderRadius: 7, color: "#c8960c", cursor: "pointer", fontSize: 12, fontWeight: 600
            }}>+ Add for this day</button>
          </div>
          {selectedTasks.length === 0 ? (
            <div style={{ textAlign: "center", padding: "32px 16px", color: "#7a5a3a", background: "#ffffff", borderRadius: 12, border: "1px dashed #f3e6c9" }}>
              <div style={{ fontSize: 32, marginBottom: 8 }}>📭</div>
              No activities logged for this day.
            </div>
          ) : (
            <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
              {selectedTasks.map(t => (
                <TaskCard key={t.id} task={t}
                  onEdit={tk => { setEditTask(tk); setShowAddModal(true); }}
                  onDelete={onDelete} />
              ))}
            </div>
          )}
        </div>
      )}

      <Modal open={showAddModal} onClose={() => { setShowAddModal(false); setEditTask(null); }}
        title={editTask ? "Edit Activity" : "Log New Activity"}>
        <TaskForm
          initial={editTask || { date: selectedDate || today() }}
          onSave={(t) => { onAddTask(t); setShowAddModal(false); setEditTask(null); }}
          onClose={() => { setShowAddModal(false); setEditTask(null); }} />
      </Modal>
    </div>
  );
};

// ─── DASHBOARD ────────────────────────────────────────────────────────────────
const Dashboard = ({ tasks, onAddTask, onDelete }) => {
  const { isMobile } = useViewport();
  const total = tasks.length;
  const completed = tasks.filter(t => t.status === "Completed").length;
  const inProgress = tasks.filter(t => t.status === "In Progress").length;
  const pending = tasks.filter(t => t.status === "Pending").length;
  const totalHours = tasks.reduce((s, t) => s + (t.duration || 0), 0);
  const [showAddModal, setShowAddModal] = useState(false);
  const [editTask, setEditTask] = useState(null);

  const catBreakdown = {};
  tasks.forEach(t => { catBreakdown[t.category] = (catBreakdown[t.category] || 0) + 1; });
  const topCats = Object.entries(catBreakdown).sort((a, b) => b[1] - a[1]).slice(0, 6);

  const recent = [...tasks].sort((a, b) => b.date.localeCompare(a.date)).slice(0, 5);

  return (
    <div>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 24, flexWrap: "wrap", gap: 10 }}>
        <h2 style={{ margin: 0, color: "#8a1414", fontSize: isMobile ? 17 : 20 }}>🏛️ Dashboard</h2>
        <button onClick={() => setShowAddModal(true)} style={{
          padding: "10px 18px", background: "linear-gradient(135deg, #c8960c, #e6b020)",
          border: "none", borderRadius: 8, color: "#1a0e02",
          fontWeight: 700, cursor: "pointer", fontSize: 13
        }}>+ Log Activity</button>
      </div>

      {/* Stats */}
      <div style={{ display: "grid", gridTemplateColumns: isMobile ? "repeat(2, 1fr)" : "repeat(auto-fill, minmax(160px, 1fr))", gap: isMobile ? 10 : 14, marginBottom: 28 }}>
        <StatCard icon="📋" label="Total Activities" value={total} sub="All time" />
        <StatCard icon="✅" label="Completed" value={completed} color="#22c55e" sub={total ? `${Math.round(completed / total * 100)}% done` : ""} />
        <StatCard icon="🔄" label="In Progress" value={inProgress} color="#f59e0b" />
        <StatCard icon="⏳" label="Pending" value={pending} color="#6366f1" />
        <StatCard icon="⏱️" label="Hours Logged" value={`${totalHours}h`} color="#c8960c" sub="Total effort" />
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr", gap: 20, marginBottom: 20 }}>
        {/* Category Breakdown */}
        <div style={{ background: "#ffffff", border: "1px solid #f3e6c9", borderRadius: 14, padding: isMobile ? 16 : 20 }}>
          <h3 style={{ margin: "0 0 16px", color: "#8a1414", fontSize: 15 }}>Activity by Category</h3>
          {topCats.length === 0 ? (
            <div style={{ color: "#7a5a3a", fontSize: 13, textAlign: "center", padding: "20px 0" }}>No activities yet</div>
          ) : topCats.map(([cat, count]) => {
            const pct = Math.round(count / total * 100);
            return (
              <div key={cat} style={{ marginBottom: 12 }}>
                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                  <span style={{ color: "#3a1010", fontSize: 13 }}>{catIcon(cat)} {cat}</span>
                  <span style={{ color: "#c8960c", fontSize: 12, fontWeight: 700 }}>{count} ({pct}%)</span>
                </div>
                <div style={{ background: "#f3e6c9", borderRadius: 4, height: 6, overflow: "hidden" }}>
                  <div style={{ width: `${pct}%`, height: "100%", background: "linear-gradient(90deg, #c8960c, #e6b020)", borderRadius: 4, transition: "width 0.6s" }} />
                </div>
              </div>
            );
          })}
        </div>

        {/* Status Distribution */}
        <div style={{ background: "#ffffff", border: "1px solid #f3e6c9", borderRadius: 14, padding: isMobile ? 16 : 20 }}>
          <h3 style={{ margin: "0 0 16px", color: "#8a1414", fontSize: 15 }}>Status Overview</h3>
          {[["Completed", completed, "#22c55e"], ["In Progress", inProgress, "#f59e0b"], ["Pending", pending, "#6366f1"], ["Cancelled", tasks.filter(t => t.status === "Cancelled").length, "#ef4444"]].map(([s, c, col]) => (
            <div key={s} style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 14 }}>
              <div style={{ width: 10, height: 10, borderRadius: "50%", background: col, flexShrink: 0 }} />
              <span style={{ color: "#3a1010", fontSize: 13, flex: 1 }}>{s}</span>
              <span style={{ color: col, fontWeight: 700, fontSize: 15 }}>{c}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Recent Activities */}
      <div style={{ background: "#ffffff", border: "1px solid #f3e6c9", borderRadius: 14, padding: isMobile ? 16 : 20 }}>
        <h3 style={{ margin: "0 0 16px", color: "#8a1414", fontSize: 15 }}>Recent Activities</h3>
        {recent.length === 0 ? (
          <div style={{ textAlign: "center", padding: "24px 0", color: "#7a5a3a" }}>
            <div style={{ fontSize: 32, marginBottom: 8 }}>🌟</div>
            <div>No activities yet. Start logging your work!</div>
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            {recent.map(t => <TaskCard key={t.id} task={t} onEdit={tk => { setEditTask(tk); setShowAddModal(true); }} onDelete={onDelete} />)}
          </div>
        )}
      </div>

      <Modal open={showAddModal} onClose={() => { setShowAddModal(false); setEditTask(null); }} title={editTask ? "Edit Activity" : "Log New Activity"}>
        <TaskForm initial={editTask || {}}
          onSave={(t) => { onAddTask(t); setShowAddModal(false); setEditTask(null); }}
          onClose={() => { setShowAddModal(false); setEditTask(null); }} />
      </Modal>
    </div>
  );
};

// ─── ALL TASKS VIEW ───────────────────────────────────────────────────────────
const AllTasks = ({ tasks, onSave, onDelete }) => {
  const { isMobile } = useViewport();
  const [filter, setFilter] = useState({ status: "", category: "", priority: "", search: "" });
  const [editTask, setEditTask] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [showFilters, setShowFilters] = useState(!isMobile);

  const filtered = tasks.filter(t => {
    if (filter.status && t.status !== filter.status) return false;
    if (filter.category && t.category !== filter.category) return false;
    if (filter.priority && t.priority !== filter.priority) return false;
    if (filter.search && !t.title.toLowerCase().includes(filter.search.toLowerCase())) return false;
    return true;
  }).sort((a, b) => b.date.localeCompare(a.date));

  const selStyle = { ...inputStyle, padding: "10px 10px", fontSize: 13 };

  return (
    <div>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 16, flexWrap: "wrap", gap: 10 }}>
        <h2 style={{ margin: 0, color: "#8a1414", fontSize: isMobile ? 17 : 20 }}>📋 All Activities</h2>
        <button onClick={() => { setEditTask(null); setShowModal(true); }} style={{
          padding: "10px 18px", background: "linear-gradient(135deg, #c8960c, #e6b020)",
          border: "none", borderRadius: 8, color: "#1a0e02",
          fontWeight: 700, cursor: "pointer", fontSize: 13
        }}>+ Log Activity</button>
      </div>

      {isMobile && (
        <button onClick={() => setShowFilters(p => !p)} style={{
          width: "100%", padding: "10px 0", marginBottom: 10, background: "#fbf3e699",
          border: "1px solid #f3e6c9", borderRadius: 8, color: "#7a5a3a", fontSize: 13, fontWeight: 600
        }}>{showFilters ? "Hide filters ▲" : "Show filters ▼"}</button>
      )}

      {/* Filters */}
      {showFilters && (
        <div style={{ display: "grid", gridTemplateColumns: isMobile ? "1fr 1fr" : "1fr 1fr 1fr 1fr", gap: 10, marginBottom: 16 }}>
          <input placeholder="Search activities..." style={{ ...selStyle, gridColumn: isMobile ? "1 / -1" : "auto" }}
            value={filter.search} onChange={e => setFilter(p => ({ ...p, search: e.target.value }))} />
          <select style={selStyle} value={filter.status} onChange={e => setFilter(p => ({ ...p, status: e.target.value }))}>
            <option value="">All Status</option>
            {STATUS_OPTIONS.map(s => <option key={s}>{s}</option>)}
          </select>
          <select style={selStyle} value={filter.category} onChange={e => setFilter(p => ({ ...p, category: e.target.value }))}>
            <option value="">All Categories</option>
            {ACTIVITY_CATEGORIES.map(c => <option key={c}>{c}</option>)}
          </select>
          <select style={selStyle} value={filter.priority} onChange={e => setFilter(p => ({ ...p, priority: e.target.value }))}>
            <option value="">All Priority</option>
            {PRIORITY.map(p => <option key={p}>{p}</option>)}
          </select>
        </div>
      )}

      <div style={{ color: "#7a5a3a", fontSize: 12, marginBottom: 12 }}>
        Showing {filtered.length} of {tasks.length} activities
      </div>

      {filtered.length === 0 ? (
        <div style={{ textAlign: "center", padding: "40px 16px", color: "#7a5a3a", background: "#ffffff", borderRadius: 12, border: "1px dashed #f3e6c9" }}>
          <div style={{ fontSize: 40, marginBottom: 10 }}>🔍</div>
          <div style={{ fontSize: 15, marginBottom: 4 }}>No activities found</div>
          <div style={{ fontSize: 13 }}>Try adjusting your filters or log a new activity.</div>
        </div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {filtered.map(t => (
            <TaskCard key={t.id} task={t}
              onEdit={tk => { setEditTask(tk); setShowModal(true); }}
              onDelete={onDelete} />
          ))}
        </div>
      )}

      <Modal open={showModal} onClose={() => { setShowModal(false); setEditTask(null); }}
        title={editTask ? "Edit Activity" : "Log New Activity"}>
        <TaskForm initial={editTask || {}}
          onSave={(t) => { onSave(t); setShowModal(false); setEditTask(null); }}
          onClose={() => { setShowModal(false); setEditTask(null); }} />
      </Modal>
    </div>
  );
};

// ─── MEMBER FORM ──────────────────────────────────────────────────────────────
const MemberForm = ({ initial, onSave, onClose }) => {
  const { isMobile } = useViewport();
  const [form, setForm] = useState({
    name: "", phone: "", role: MEMBER_ROLES[0],
    status: "Invited", notes: "",
    ...initial
  });
  const [err, setErr] = useState("");
  const set = (k, v) => setForm(p => ({ ...p, [k]: v }));

  const handleSave = () => {
    if (!form.name.trim()) return setErr("Please enter the member's name.");
    const digits = form.phone.replace(/[^\d+]/g, "");
    if (digits.replace("+", "").length < 10) return setErr("Please enter a valid WhatsApp number with country code (e.g. +919876543210).");
    setErr("");
    onSave({ ...form, phone: digits, id: form.id || `m${Date.now()}`, invitedAt: form.invitedAt || today() });
  };

  return (
    <div>
      <Field label="Full Name">
        <input style={inputStyle} value={form.name}
          onChange={e => set("name", e.target.value)} placeholder="e.g. Anita Maheshwari" />
      </Field>
      <Field label="WhatsApp Number (with country code)">
        <input style={inputStyle} value={form.phone}
          onChange={e => set("phone", e.target.value)} placeholder="+919876543210" />
      </Field>
      <div style={{ display: "grid", gridTemplateColumns: isMobile ? "1fr" : "1fr 1fr", gap: 12 }}>
        <Field label="Role">
          <select style={inputStyle} value={form.role} onChange={e => set("role", e.target.value)}>
            {MEMBER_ROLES.map(r => <option key={r}>{r}</option>)}
          </select>
        </Field>
        <Field label="Status">
          <select style={inputStyle} value={form.status} onChange={e => set("status", e.target.value)}>
            {MEMBER_STATUS.map(s => <option key={s}>{s}</option>)}
          </select>
        </Field>
      </div>
      <Field label="Notes (optional)">
        <textarea style={{ ...inputStyle, minHeight: 60, resize: "vertical" }}
          value={form.notes} onChange={e => set("notes", e.target.value)}
          placeholder="Any additional details..." />
      </Field>

      {err && (
        <div style={{ background: "#fde8e8", border: "1px solid #e08a8a", borderRadius: 8, padding: "10px 14px", color: "#ef4444", fontSize: 13, marginBottom: 16 }}>{err}</div>
      )}

      <div style={{ display: "flex", gap: 10, justifyContent: "flex-end", marginTop: 8, flexDirection: isMobile ? "column-reverse" : "row" }}>
        <button onClick={onClose} style={{
          padding: "12px 20px", background: "transparent",
          border: "1px solid #d9c195", borderRadius: 8,
          color: "#7a5a3a", cursor: "pointer", fontSize: 14, width: isMobile ? "100%" : "auto"
        }}>Cancel</button>
        <button onClick={handleSave} style={{
          padding: "12px 24px", background: "linear-gradient(135deg, #c8960c, #e6b020)",
          border: "none", borderRadius: 8, color: "#1a0e02",
          fontWeight: 700, cursor: "pointer", fontSize: 14, width: isMobile ? "100%" : "auto"
        }}>Save Member</button>
      </div>
    </div>
  );
};

// ─── MEMBER CARD ──────────────────────────────────────────────────────────────
const MemberCard = ({ member, onEdit, onDelete, onInvite, onApprove }) => {
  const { isMobile } = useViewport();
  const initials = (member.name || "?").trim().split(" ").map(w => w[0]).join("").slice(0, 2).toUpperCase();
  const isPending = member.status === "Pending";
  return (
    <div style={{
      background: isPending ? "#fff9ed" : "#ffffff", border: isPending ? "1px solid #e6c87a" : "1px solid #f3e6c9",
      borderRadius: 12, padding: isMobile ? 14 : 16,
      boxShadow: "0 1px 3px rgba(138,20,20,0.06)",
      display: "flex", alignItems: "flex-start", gap: 12, flexWrap: isMobile ? "wrap" : "nowrap"
    }}>
      <Avatar initials={initials} size={38} />
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap", marginBottom: 6 }}>
          <span style={{ color: "#3a1010", fontWeight: 600, fontSize: 14 }}>{member.name}</span>
          <Badge label={member.status} color={memberStatusColor(member.status)} />
        </div>
        <div style={{ display: "flex", gap: 12, flexWrap: "wrap", fontSize: 12, color: "#7a5a3a" }}>
          <span>📱 {member.phone}</span>
          <span>🏷️ {member.role}</span>
        </div>
        {member.notes && <p style={{ margin: "8px 0 0", color: "#8a6a48", fontSize: 13, lineHeight: 1.5 }}>{member.notes}</p>}
      </div>
      <div style={{ display: "flex", gap: 6, flexShrink: 0, flexWrap: "wrap" }}>
        {isPending && (
          <button onClick={() => onApprove(member)} style={{
            background: "#dcf8c6", border: "1px solid #b6e6a0", borderRadius: 6,
            color: "#1a8a4a", cursor: "pointer", padding: "6px 10px", fontSize: 12, fontWeight: 700,
            whiteSpace: "nowrap"
          }}>✅ Approve</button>
        )}
        <button onClick={() => onInvite(member)} style={{
          background: "#dcf8c6", border: "1px solid #b6e6a0", borderRadius: 6,
          color: "#1a8a4a", cursor: "pointer", padding: "6px 10px", fontSize: 12, fontWeight: 600,
          whiteSpace: "nowrap"
        }}>💬 WhatsApp Invite</button>
        <button onClick={() => onEdit(member)} style={{
          background: "#f3e6c9", border: "1px solid #d9c195", borderRadius: 6,
          color: "#c8960c", cursor: "pointer", padding: "6px 10px", fontSize: 12
        }}>Edit</button>
        <button onClick={() => onDelete(member.id)} style={{
          background: "#fde8e8", border: "1px solid #e08a8a", borderRadius: 6,
          color: "#ef4444", cursor: "pointer", padding: "6px 10px", fontSize: 12
        }}>✕</button>
      </div>
    </div>
  );
};

// ─── MEMBERS PANEL ────────────────────────────────────────────────────────────
const Members = ({ members, onSave, onDelete }) => {
  const { isMobile } = useViewport();
  const [filter, setFilter] = useState({ status: "", search: "" });
  const [editMember, setEditMember] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [showFilters, setShowFilters] = useState(!isMobile);
  const [linkCopied, setLinkCopied] = useState(false);

  const filtered = members.filter(m => {
    if (filter.status && m.status !== filter.status) return false;
    if (filter.search && !m.name.toLowerCase().includes(filter.search.toLowerCase()) && !m.phone.includes(filter.search)) return false;
    return true;
  }).sort((a, b) => a.name.localeCompare(b.name));

  const selStyle = { ...inputStyle, padding: "10px 10px", fontSize: 13 };

  const handleInvite = (member) => {
    window.open(buildWhatsAppInviteUrl(member), "_blank");
    if (member.status === "Invited" && !member.invitedAt) {
      onSave({ ...member, invitedAt: today() });
    }
  };

  const handleApprove = (member) => {
    onSave({ ...member, status: "Active" });
    window.open(buildWhatsAppApprovalUrl(member), "_blank");
  };

  const total = members.length;
  const active = members.filter(m => m.status === "Active").length;
  const invited = members.filter(m => m.status === "Invited").length;
  const pending = members.filter(m => m.status === "Pending").length;

  const copyJoinLink = async () => {
    try {
      await navigator.clipboard.writeText(JOIN_URL);
      setLinkCopied(true);
      setTimeout(() => setLinkCopied(false), 2000);
    } catch {
      // Clipboard API unavailable — fall back to selecting via prompt.
      window.prompt("Copy this join link:", JOIN_URL);
    }
  };

  return (
    <div>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 16, flexWrap: "wrap", gap: 10 }}>
        <h2 style={{ margin: 0, color: "#8a1414", fontSize: isMobile ? 17 : 20 }}>👥 Members</h2>
        <button onClick={() => { setEditMember(null); setShowModal(true); }} style={{
          padding: "10px 18px", background: "linear-gradient(135deg, #c8960c, #e6b020)",
          border: "none", borderRadius: 8, color: "#1a0e02",
          fontWeight: 700, cursor: "pointer", fontSize: 13
        }}>+ Add Member</button>
      </div>

      <div style={{
        display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap",
        background: "#fdf8f2", border: "1px solid #f3e6c9", borderRadius: 10,
        padding: "10px 14px", marginBottom: 16
      }}>
        <span style={{ fontSize: 12.5, color: "#7a5a3a", flexShrink: 0 }}>🔗 Join link:</span>
        <span style={{
          fontSize: 12.5, color: "#3a1010", flex: 1, minWidth: 0,
          overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap"
        }}>{JOIN_URL}</span>
        <button onClick={copyJoinLink} style={{
          padding: "6px 12px", background: linkCopied ? "#dcf8c6" : "#f3e6c9",
          border: `1px solid ${linkCopied ? "#b6e6a0" : "#d9c195"}`, borderRadius: 6,
          color: linkCopied ? "#1a8a4a" : "#7a5a3a", cursor: "pointer", fontSize: 12, fontWeight: 600,
          whiteSpace: "nowrap", flexShrink: 0
        }}>{linkCopied ? "✓ Copied" : "Copy"}</button>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: isMobile ? "repeat(3, 1fr)" : "repeat(auto-fill, minmax(140px, 1fr))", gap: isMobile ? 8 : 12, marginBottom: 18 }}>
        <StatCard icon="👥" label="Total Members" value={total} sub="All members" />
        <StatCard icon="🆕" label="Pending Approval" value={pending} color="#8a1414" />
        <StatCard icon="✅" label="Active" value={active} color="#22c55e" />
        <StatCard icon="✉️" label="Invited" value={invited} color="#f59e0b" />
      </div>

      {isMobile && (
        <button onClick={() => setShowFilters(p => !p)} style={{
          width: "100%", padding: "10px 0", marginBottom: 10, background: "#fbf3e699",
          border: "1px solid #f3e6c9", borderRadius: 8, color: "#7a5a3a", fontSize: 13, fontWeight: 600
        }}>{showFilters ? "Hide filters ▲" : "Show filters ▼"}</button>
      )}

      {showFilters && (
        <div style={{ display: "grid", gridTemplateColumns: isMobile ? "1fr 1fr" : "2fr 1fr", gap: 10, marginBottom: 16 }}>
          <input placeholder="Search name or phone..." style={{ ...selStyle, gridColumn: isMobile ? "1 / -1" : "auto" }}
            value={filter.search} onChange={e => setFilter(p => ({ ...p, search: e.target.value }))} />
          <select style={selStyle} value={filter.status} onChange={e => setFilter(p => ({ ...p, status: e.target.value }))}>
            <option value="">All Status</option>
            {MEMBER_STATUS.map(s => <option key={s}>{s}</option>)}
          </select>
        </div>
      )}

      <div style={{ color: "#7a5a3a", fontSize: 12, marginBottom: 12 }}>
        Showing {filtered.length} of {members.length} members
      </div>

      {filtered.length === 0 ? (
        <div style={{ textAlign: "center", padding: "40px 16px", color: "#7a5a3a", background: "#ffffff", borderRadius: 12, border: "1px dashed #f3e6c9" }}>
          <div style={{ fontSize: 40, marginBottom: 10 }}>👥</div>
          <div style={{ fontSize: 15, marginBottom: 4 }}>No members found</div>
          <div style={{ fontSize: 13 }}>Add a member, or share the join link so members can request to join themselves.</div>
        </div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {filtered.map(m => (
            <MemberCard key={m.id} member={m}
              onEdit={mb => { setEditMember(mb); setShowModal(true); }}
              onDelete={onDelete}
              onInvite={handleInvite}
              onApprove={handleApprove} />
          ))}
        </div>
      )}

      <Modal open={showModal} onClose={() => { setShowModal(false); setEditMember(null); }}
        title={editMember ? "Edit Member" : "Add New Member"}>
        <MemberForm initial={editMember || {}}
          onSave={(m) => {
            const isNew = !editMember;
            onSave(m);
            setShowModal(false);
            setEditMember(null);
            // Auto-open the WhatsApp invite the moment an admin adds someone new.
            // The browser can't send WhatsApp messages on its own — there's no
            // backend here — so this is the closest thing to "automatic": the
            // chat opens pre-filled and the admin just taps Send.
            if (isNew) window.open(buildWhatsAppInviteUrl(m), "_blank");
          }}
          onClose={() => { setShowModal(false); setEditMember(null); }} />
      </Modal>
    </div>
  );
};

// ─── BRAND HEADER (shared by setup/login) ──────────────────────────────────────
const BrandHeader = ({ isMobile }) => (
  <div style={{ textAlign: "center", marginBottom: isMobile ? 26 : 32 }}>
    <img src={LOGO_SRC} alt={ORG_NAME_EN} style={{
      width: isMobile ? 84 : 104, height: isMobile ? 84 : 104, borderRadius: "50%", marginBottom: 14,
      boxShadow: "0 6px 20px rgba(138,20,20,0.25)", border: "3px solid #c8960c"
    }} />
    <h1 style={{ margin: "0 0 2px", color: "#8a1414", fontSize: isMobile ? 18 : 22, fontWeight: 800, letterSpacing: 0.3, lineHeight: 1.3 }}>
      {ORG_NAME}
    </h1>
    <div style={{ color: "#a9821a", fontSize: 11.5, fontWeight: 700, letterSpacing: 0.6, textTransform: "uppercase", marginBottom: 6 }}>
      {ORG_NAME_EN}
    </div>
    <p style={{ margin: 0, color: "#7a5a3a", fontSize: 14, fontWeight: 600 }}>{APP_NAME}</p>
  </div>
);

const AuthShell = ({ children, isMobile }) => (
  <div style={{
    minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center",
    background: "radial-gradient(circle at 50% 0%, #fff6e6 0%, #ffffff 55%)", padding: isMobile ? 16 : 20
  }}>
    <div style={{ width: "100%", maxWidth: 420 }}>{children}</div>
  </div>
);

// ─── FIRST-RUN SETUP SCREEN ─────────────────────────────────────────────────────
// Shown only once, when no admin account exists yet on this deployment.
// After this, public self-registration is disabled — only this superadmin
// can create further admin accounts, from Settings → Manage Admins.
const SetupAccount = ({ onCreated }) => {
  const { isMobile } = useViewport();
  const [name, setName] = useState("Admin");
  const [pw, setPw] = useState("");
  const [pw2, setPw2] = useState("");
  const [err, setErr] = useState("");
  const [busy, setBusy] = useState(false);

  const handle = async () => {
    setErr("");
    if (!name.trim()) return setErr("Please enter your name.");
    if (pw.length < 6) return setErr("Password must be at least 6 characters.");
    if (pw !== pw2) return setErr("Passwords do not match.");
    setBusy(true);
    const passwordHash = await hashPassword(pw);
    const account = {
      id: `a${Date.now()}`,
      name: name.trim(),
      avatar: name.trim().split(" ").map(w => w[0]).join("").slice(0, 2).toUpperCase() || "AD",
      passwordHash, role: "superadmin"
    };
    await setToStorage("njms_accounts", [account]);
    setBusy(false);
    onCreated(account);
  };

  return (
    <AuthShell isMobile={isMobile}>
      <BrandHeader isMobile={isMobile} />
      <div style={{ background: "#ffffff", border: "1px solid #d9c195", borderRadius: 20, padding: isMobile ? 22 : 32, boxShadow: "0 8px 28px rgba(138,20,20,0.08)" }}>
        <h2 style={{ margin: "0 0 6px", color: "#3a1010", fontSize: 18, fontWeight: 700 }}>Create the super admin account</h2>
        <p style={{ margin: "0 0 22px", color: "#7a5a3a", fontSize: 13, lineHeight: 1.5 }}>
          This is a one-time setup, shown only because no admin exists yet. Once created, public sign-up is disabled —
          you'll be the only one who can add other admins, from Settings.
        </p>

        <Field label="Your Name">
          <input style={inputStyle} value={name} onChange={e => setName(e.target.value)} placeholder="e.g. Varun Gandhi" />
        </Field>
        <Field label="Password">
          <input type="password" style={inputStyle} value={pw} onChange={e => setPw(e.target.value)} placeholder="At least 6 characters" />
        </Field>
        <Field label="Confirm Password">
          <input type="password" style={inputStyle} value={pw2}
            onChange={e => setPw2(e.target.value)}
            onKeyDown={e => e.key === "Enter" && handle()}
            placeholder="Re-enter password" />
        </Field>

        {err && (
          <div style={{ background: "#fde8e8", border: "1px solid #e08a8a", borderRadius: 8, padding: "10px 14px", color: "#ef4444", fontSize: 13, marginBottom: 16 }}>{err}</div>
        )}

        <button onClick={handle} disabled={busy} style={{
          width: "100%", padding: "13px 0", marginTop: 4,
          background: "linear-gradient(135deg, #c8960c, #e6b020)",
          border: "none", borderRadius: 10, color: "#1a0e02",
          fontWeight: 800, fontSize: 15, cursor: busy ? "default" : "pointer", letterSpacing: 0.4,
          opacity: busy ? 0.7 : 1
        }}>{busy ? "Setting up..." : "Create Account & Sign In"}</button>
      </div>
    </AuthShell>
  );
};

// ─── MEMBER SIGN-UP SCREEN (public, no login created) ──────────────────────────
// Anyone with the link can submit this form. It does NOT create a login or
// grant any access — it just adds a member record with status "Pending".
// An admin must review it in Members and tap Approve before the person is
// considered an active member. This is intentionally one-way: members never
// get an account or password in this app.
const MemberSignup = ({ onSubmit, onBackToLogin }) => {
  const { isMobile } = useViewport();
  const [form, setForm] = useState({ name: "", phone: "" });
  const [err, setErr] = useState("");
  const [done, setDone] = useState(false);
  const set = (k, v) => setForm(p => ({ ...p, [k]: v }));

  const handle = () => {
    setErr("");
    if (!form.name.trim()) return setErr("Please enter your name.");
    const digits = form.phone.replace(/[^\d+]/g, "");
    if (digits.replace("+", "").length < 10) return setErr("Please enter a valid WhatsApp number with country code (e.g. +919876543210).");
    onSubmit({
      id: `m${Date.now()}`,
      name: form.name.trim(),
      phone: digits,
      role: "Member",
      status: "Pending",
      invitedAt: today()
    });
    setDone(true);
  };

  if (done) {
    return (
      <AuthShell isMobile={isMobile}>
        <BrandHeader isMobile={isMobile} />
        <div style={{ background: "#ffffff", border: "1px solid #d9c195", borderRadius: 20, padding: isMobile ? 22 : 32, boxShadow: "0 8px 28px rgba(138,20,20,0.08)", textAlign: "center" }}>
          <div style={{ fontSize: 40, marginBottom: 10 }}>✅</div>
          <h2 style={{ margin: "0 0 8px", color: "#3a1010", fontSize: 17, fontWeight: 700 }}>Request received</h2>
          <p style={{ margin: "0 0 20px", color: "#7a5a3a", fontSize: 13.5, lineHeight: 1.6 }}>
            Thanks, {form.name}! Your request to join {ORG_NAME_EN} has been sent to the admins for approval.
            You'll get a message on WhatsApp once it's confirmed.
          </p>
          <button onClick={onBackToLogin} style={{
            padding: "10px 18px", background: "transparent", border: "1px solid #d9c195",
            borderRadius: 8, color: "#7a5a3a", cursor: "pointer", fontSize: 13
          }}>Back to sign in</button>
        </div>
      </AuthShell>
    );
  }

  return (
    <AuthShell isMobile={isMobile}>
      <BrandHeader isMobile={isMobile} />
      <div style={{ background: "#ffffff", border: "1px solid #d9c195", borderRadius: 20, padding: isMobile ? 22 : 32, boxShadow: "0 8px 28px rgba(138,20,20,0.08)" }}>
        <h2 style={{ margin: "0 0 6px", color: "#3a1010", fontSize: 18, fontWeight: 700 }}>Join the Sabha</h2>
        <p style={{ margin: "0 0 20px", color: "#7a5a3a", fontSize: 13, lineHeight: 1.5 }}>
          Fill this in to request membership. An admin will review and approve your request — you'll be notified on WhatsApp.
        </p>

        <Field label="Full Name">
          <input style={inputStyle} value={form.name} onChange={e => set("name", e.target.value)}
            placeholder="Your name" autoFocus />
        </Field>
        <Field label="WhatsApp Number (with country code)">
          <input style={inputStyle} value={form.phone} onChange={e => set("phone", e.target.value)}
            placeholder="+919876543210" />
        </Field>

        {err && (
          <div style={{ background: "#fde8e8", border: "1px solid #e08a8a", borderRadius: 8, padding: "10px 14px", color: "#ef4444", fontSize: 13, marginBottom: 16 }}>{err}</div>
        )}

        <button onClick={handle} style={{
          width: "100%", padding: "13px 0", marginTop: 4,
          background: "linear-gradient(135deg, #c8960c, #e6b020)",
          border: "none", borderRadius: 10, color: "#1a0e02",
          fontWeight: 800, fontSize: 15, cursor: "pointer", letterSpacing: 0.4
        }}>Request to Join</button>

        <button onClick={onBackToLogin} style={{
          width: "100%", padding: "10px 0", marginTop: 10, background: "transparent",
          border: "none", color: "#7a5a3a", cursor: "pointer", fontSize: 12.5, textDecoration: "underline"
        }}>I'm an admin — back to sign in</button>
      </div>
    </AuthShell>
  );
};

// ─── LOGIN SCREEN ─────────────────────────────────────────────────────────────
// Public self-registration is disabled. The person logging in picks their
// name from the existing admin accounts (created either at first-run setup,
// or by the superadmin via Settings → Manage Admins) and enters their password.
const Login = ({ accounts, onLogin, onShowSignup }) => {
  const { isMobile } = useViewport();
  const [selectedId, setSelectedId] = useState(accounts[0]?.id || "");
  const [pw, setPw] = useState("");
  const [err, setErr] = useState("");

  const selected = accounts.find(a => a.id === selectedId) || accounts[0];

  const handle = async () => {
    const h = await hashPassword(pw);
    if (selected && h === selected.passwordHash) { setErr(""); onLogin(selected.id); }
    else setErr("Incorrect password. Please try again.");
  };

  return (
    <AuthShell isMobile={isMobile}>
      <BrandHeader isMobile={isMobile} />
      <div style={{ background: "#ffffff", border: "1px solid #d9c195", borderRadius: 20, padding: isMobile ? 22 : 32, boxShadow: "0 8px 28px rgba(138,20,20,0.08)" }}>
        {accounts.length > 1 ? (
          <Field label="Sign in as">
            <select style={inputStyle} value={selectedId} onChange={e => { setSelectedId(e.target.value); setErr(""); }}>
              {accounts.map(a => <option key={a.id} value={a.id}>{a.name} ({a.role === "superadmin" ? "Super Admin" : "Admin"})</option>)}
            </select>
          </Field>
        ) : (
          <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 22 }}>
            <Avatar initials={selected.avatar} size={40} />
            <div>
              <div style={{ color: "#3a1010", fontWeight: 700, fontSize: 15 }}>{selected.name}</div>
              <div style={{ color: "#7a5a3a", fontSize: 12 }}>Welcome back</div>
            </div>
          </div>
        )}

        <Field label="Password">
          <input type="password" style={inputStyle} value={pw}
            onChange={e => setPw(e.target.value)}
            onKeyDown={e => e.key === "Enter" && handle()}
            placeholder="Enter your password" autoFocus />
        </Field>

        {err && (
          <div style={{ background: "#fde8e8", border: "1px solid #e08a8a", borderRadius: 8, padding: "10px 14px", color: "#ef4444", fontSize: 13, marginBottom: 16 }}>{err}</div>
        )}

        <button onClick={handle} style={{
          width: "100%", padding: "13px 0", marginTop: 4,
          background: "linear-gradient(135deg, #c8960c, #e6b020)",
          border: "none", borderRadius: 10, color: "#1a0e02",
          fontWeight: 800, fontSize: 15, cursor: "pointer", letterSpacing: 0.4
        }}>Sign In</button>

        <button onClick={onShowSignup} style={{
          width: "100%", padding: "10px 0", marginTop: 10, background: "transparent",
          border: "none", color: "#7a5a3a", cursor: "pointer", fontSize: 12.5, textDecoration: "underline"
        }}>I'm a community member — request to join</button>
      </div>
    </AuthShell>
  );
};

// ─── ADD ADMIN FORM (superadmin only) ──────────────────────────────────────────
const AdminForm = ({ onSave, onClose }) => {
  const { isMobile } = useViewport();
  const [name, setName] = useState("");
  const [pw, setPw] = useState("");
  const [pw2, setPw2] = useState("");
  const [err, setErr] = useState("");

  const handle = async () => {
    if (!name.trim()) return setErr("Please enter a name.");
    if (pw.length < 6) return setErr("Password must be at least 6 characters.");
    if (pw !== pw2) return setErr("Passwords do not match.");
    setErr("");
    const passwordHash = await hashPassword(pw);
    onSave({
      id: `a${Date.now()}`,
      name: name.trim(),
      avatar: name.trim().split(" ").map(w => w[0]).join("").slice(0, 2).toUpperCase() || "AD",
      passwordHash, role: "admin"
    });
  };

  return (
    <div>
      <Field label="Name">
        <input style={inputStyle} value={name} onChange={e => setName(e.target.value)} placeholder="e.g. Priya Rathi" />
      </Field>
      <Field label="Temporary Password">
        <input type="password" style={inputStyle} value={pw} onChange={e => setPw(e.target.value)} placeholder="At least 6 characters" />
      </Field>
      <Field label="Confirm Password">
        <input type="password" style={inputStyle} value={pw2} onChange={e => setPw2(e.target.value)} />
      </Field>
      {err && (
        <div style={{ background: "#fde8e8", border: "1px solid #e08a8a", borderRadius: 8, padding: "10px 14px", color: "#ef4444", fontSize: 13, marginBottom: 16 }}>{err}</div>
      )}
      <div style={{ display: "flex", gap: 10, justifyContent: "flex-end", flexDirection: isMobile ? "column-reverse" : "row" }}>
        <button onClick={onClose} style={{
          padding: "12px 20px", background: "transparent", border: "1px solid #d9c195", borderRadius: 8,
          color: "#7a5a3a", cursor: "pointer", fontSize: 14, width: isMobile ? "100%" : "auto"
        }}>Cancel</button>
        <button onClick={handle} style={{
          padding: "12px 24px", background: "linear-gradient(135deg, #c8960c, #e6b020)",
          border: "none", borderRadius: 8, color: "#1a0e02",
          fontWeight: 700, cursor: "pointer", fontSize: 14, width: isMobile ? "100%" : "auto"
        }}>Add Admin</button>
      </div>
    </div>
  );
};

// ─── SETTINGS (change password, manage admins) ─────────────────────────────────
const Settings = ({ account, accounts, onUpdateAccount, onAddAdmin, onRemoveAdmin, onLogout }) => {
  const { isMobile } = useViewport();
  const [name, setName] = useState(account.name);
  const [curPw, setCurPw] = useState("");
  const [newPw, setNewPw] = useState("");
  const [newPw2, setNewPw2] = useState("");
  const [msg, setMsg] = useState(null); // { type: 'error'|'success', text }
  const [showAdminModal, setShowAdminModal] = useState(false);
  const [removeTarget, setRemoveTarget] = useState(null);

  const saveName = async () => {
    if (!name.trim()) return setMsg({ type: "error", text: "Name cannot be empty." });
    const updated = { ...account, name: name.trim(), avatar: name.trim().split(" ").map(w => w[0]).join("").slice(0, 2).toUpperCase() || "AD" };
    onUpdateAccount(updated);
    setMsg({ type: "success", text: "Name updated." });
  };

  const changePassword = async () => {
    setMsg(null);
    const curHash = await hashPassword(curPw);
    if (curHash !== account.passwordHash) return setMsg({ type: "error", text: "Current password is incorrect." });
    if (newPw.length < 6) return setMsg({ type: "error", text: "New password must be at least 6 characters." });
    if (newPw !== newPw2) return setMsg({ type: "error", text: "New passwords do not match." });
    const newHash = await hashPassword(newPw);
    onUpdateAccount({ ...account, passwordHash: newHash });
    setCurPw(""); setNewPw(""); setNewPw2("");
    setMsg({ type: "success", text: "Password updated successfully." });
  };

  const card = { background: "#ffffff", border: "1px solid #f3e6c9", borderRadius: 14, padding: isMobile ? 18 : 22, marginBottom: 18 };

  return (
    <div style={{ maxWidth: 560 }}>
      <h2 style={{ margin: "0 0 20px", color: "#8a1414", fontSize: isMobile ? 17 : 20 }}>⚙️ Settings</h2>

      {msg && (
        <div style={{
          background: msg.type === "error" ? "#fde8e8" : "#e8f9ee",
          border: `1px solid ${msg.type === "error" ? "#e08a8a" : "#86d9a3"}`,
          borderRadius: 8, padding: "10px 14px",
          color: msg.type === "error" ? "#ef4444" : "#1a8a4a",
          fontSize: 13, marginBottom: 16
        }}>{msg.text}</div>
      )}

      <div style={card}>
        <h3 style={{ margin: "0 0 14px", color: "#3a1010", fontSize: 14, fontWeight: 700 }}>Profile</h3>
        <Field label="Display Name">
          <input style={inputStyle} value={name} onChange={e => setName(e.target.value)} />
        </Field>
        <button onClick={saveName} style={{
          padding: "10px 18px", background: "#f3e6c9", border: "1px solid #d9c195", borderRadius: 8,
          color: "#8a1414", fontWeight: 700, cursor: "pointer", fontSize: 13
        }}>Save Name</button>
      </div>

      <div style={card}>
        <h3 style={{ margin: "0 0 14px", color: "#3a1010", fontSize: 14, fontWeight: 700 }}>Change Password</h3>
        <Field label="Current Password">
          <input type="password" style={inputStyle} value={curPw} onChange={e => setCurPw(e.target.value)} />
        </Field>
        <Field label="New Password">
          <input type="password" style={inputStyle} value={newPw} onChange={e => setNewPw(e.target.value)} placeholder="At least 6 characters" />
        </Field>
        <Field label="Confirm New Password">
          <input type="password" style={inputStyle} value={newPw2} onChange={e => setNewPw2(e.target.value)} />
        </Field>
        <button onClick={changePassword} style={{
          padding: "10px 18px", background: "linear-gradient(135deg, #c8960c, #e6b020)",
          border: "none", borderRadius: 8, color: "#1a0e02", fontWeight: 700, cursor: "pointer", fontSize: 13
        }}>Update Password</button>
      </div>

      {account.role === "superadmin" && (
        <div style={card}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 14, flexWrap: "wrap", gap: 8 }}>
            <h3 style={{ margin: 0, color: "#3a1010", fontSize: 14, fontWeight: 700 }}>Manage Admins</h3>
            <button onClick={() => setShowAdminModal(true)} style={{
              padding: "8px 14px", background: "#f3e6c9", border: "1px solid #d9c195", borderRadius: 8,
              color: "#8a1414", fontWeight: 700, cursor: "pointer", fontSize: 12
            }}>+ Add Admin</button>
          </div>
          <p style={{ margin: "0 0 14px", color: "#7a5a3a", fontSize: 12.5, lineHeight: 1.5 }}>
            Public sign-up is disabled. As the super admin, you're the only one who can create other admin accounts here.
          </p>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {accounts.map(a => (
              <div key={a.id} style={{
                display: "flex", alignItems: "center", gap: 10, padding: "8px 10px",
                background: "#fdf8f2", border: "1px solid #f3e6c9", borderRadius: 8
              }}>
                <Avatar initials={a.avatar} size={30} />
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ color: "#3a1010", fontSize: 13, fontWeight: 600 }}>{a.name}{a.id === account.id ? " (You)" : ""}</div>
                  <div style={{ color: "#7a5a3a", fontSize: 11 }}>{a.role === "superadmin" ? "Super Admin" : "Admin"}</div>
                </div>
                {a.role !== "superadmin" && (
                  <button onClick={() => setRemoveTarget(a)} style={{
                    background: "#fde8e8", border: "1px solid #e08a8a", borderRadius: 6,
                    color: "#ef4444", cursor: "pointer", padding: "6px 10px", fontSize: 12
                  }}>Remove</button>
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      <Modal open={showAdminModal} onClose={() => setShowAdminModal(false)} title="Add New Admin">
        <AdminForm onSave={(a) => { onAddAdmin(a); setShowAdminModal(false); }} onClose={() => setShowAdminModal(false)} />
      </Modal>

      <ConfirmDialog
        open={!!removeTarget}
        title="Remove admin?"
        message={removeTarget ? `Remove ${removeTarget.name} as an admin? They will no longer be able to sign in.` : ""}
        confirmLabel="Remove"
        onCancel={() => setRemoveTarget(null)}
        onConfirm={() => { onRemoveAdmin(removeTarget.id); setRemoveTarget(null); }}
      />
    </div>
  );
};

// ─── MAIN APP ─────────────────────────────────────────────────────────────────
export default function App() {
  const { isMobile } = useViewport();
  const [accounts, setAccounts] = useState([]);        // [{ id, name, avatar, passwordHash, role }]
  const [currentAccountId, setCurrentAccountId] = useState(null);
  const [authed, setAuthed] = useState(false);
  const [tasks, setTasks] = useState(SAMPLE_TASKS);
  const [members, setMembers] = useState(SAMPLE_MEMBERS);
  const [activeTab, setActiveTab] = useState("dashboard");
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [mobileNavOpen, setMobileNavOpen] = useState(false);
  const [loaded, setLoaded] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState(null); // { type: 'task'|'member', id, label }
  const [showSignup, setShowSignup] = useState(() => {
    if (typeof window === "undefined") return false;
    const path = window.location.pathname || "";
    const params = new URLSearchParams(window.location.search || "");
    return path.replace(/\/$/, "").endsWith("/join") || params.get("join") === "1";
  });

  // Load from storage
  useEffect(() => {
    (async () => {
      const savedTasks = await getFromStorage("njms_tasks");
      if (savedTasks && savedTasks.length > 0) setTasks(savedTasks);
      const savedMembers = await getFromStorage("njms_members");
      if (savedMembers && savedMembers.length > 0) setMembers(savedMembers);

      let savedAccounts = await getFromStorage("njms_accounts");
      if (!savedAccounts || savedAccounts.length === 0) {
        // Migrate from the old single-account format if present.
        const legacy = await getFromStorage("njms_account");
        if (legacy) {
          savedAccounts = [{ ...legacy, id: legacy.id || `a${Date.now()}`, role: "superadmin" }];
          await setToStorage("njms_accounts", savedAccounts);
        }
      }
      if (savedAccounts) setAccounts(savedAccounts);

      const session = await getFromStorage("njms_session", false);
      if (session && savedAccounts && savedAccounts.some(a => a.id === session)) {
        setCurrentAccountId(session);
        setAuthed(true);
      }
      setLoaded(true);
    })();
  }, []);

  // Persist tasks
  useEffect(() => {
    if (loaded) setToStorage("njms_tasks", tasks);
  }, [tasks, loaded]);

  // Persist members
  useEffect(() => {
    if (loaded) setToStorage("njms_members", members);
  }, [members, loaded]);

  // Persist accounts
  useEffect(() => {
    if (loaded) setToStorage("njms_accounts", accounts);
  }, [accounts, loaded]);

  const handleAccountCreated = (acc) => {
    setAccounts([acc]);
    setCurrentAccountId(acc.id);
    setAuthed(true);
    setToStorage("njms_session", acc.id, false);
  };

  const handleLogin = (accountId) => {
    setCurrentAccountId(accountId);
    setAuthed(true);
    setToStorage("njms_session", accountId, false);
  };

  const handleLogout = () => {
    setAuthed(false);
    setToStorage("njms_session", false, false);
  };

  const updateAccount = useCallback((updated) => {
    setAccounts(prev => prev.map(a => a.id === updated.id ? updated : a));
  }, []);

  const addAdmin = useCallback((admin) => {
    setAccounts(prev => [...prev, admin]);
  }, []);

  const removeAdmin = useCallback((id) => {
    setAccounts(prev => prev.filter(a => a.id !== id));
  }, []);

  const saveTask = useCallback((task) => {
    setTasks(prev => {
      const idx = prev.findIndex(t => t.id === task.id);
      if (idx >= 0) {
        const next = [...prev]; next[idx] = task; return next;
      }
      return [task, ...prev];
    });
  }, []);

  // window.confirm() is blocked inside this app's sandboxed environment and
  // silently no-ops, which is why delete used to appear broken. We collect
  // the intent here and confirm via our own <ConfirmDialog/> instead.
  const requestDeleteTask = useCallback((id) => {
    const t = tasks.find(x => x.id === id);
    setDeleteTarget({ type: "task", id, label: t ? t.title : "this activity" });
  }, [tasks]);

  const requestDeleteMember = useCallback((id) => {
    const m = members.find(x => x.id === id);
    setDeleteTarget({ type: "member", id, label: m ? m.name : "this member" });
  }, [members]);

  const confirmDelete = useCallback(() => {
    if (!deleteTarget) return;
    if (deleteTarget.type === "task") setTasks(prev => prev.filter(t => t.id !== deleteTarget.id));
    if (deleteTarget.type === "member") setMembers(prev => prev.filter(m => m.id !== deleteTarget.id));
    setDeleteTarget(null);
  }, [deleteTarget]);

  const saveMember = useCallback((member) => {
    setMembers(prev => {
      const idx = prev.findIndex(m => m.id === member.id);
      if (idx >= 0) {
        const next = [...prev]; next[idx] = member; return next;
      }
      return [member, ...prev];
    });
  }, []);

  if (!loaded) {
    return (
      <div style={{ minHeight: "100vh", background: "#ffffff", display: "flex", alignItems: "center", justifyContent: "center", color: "#c8960c", fontSize: 18 }}>
        <div style={{ textAlign: "center" }}>
          <img src={LOGO_SRC} alt={ORG_NAME_EN} style={{ width: 64, height: 64, borderRadius: "50%", marginBottom: 14, border: "2px solid #c8960c" }} />
          <div style={{ color: "#8a1414", fontWeight: 700 }}>Loading {APP_NAME}...</div>
        </div>
      </div>
    );
  }

  if (accounts.length === 0) return <SetupAccount onCreated={handleAccountCreated} />;
  if (!authed) {
    if (showSignup) {
      return <MemberSignup onSubmit={(m) => { saveMember(m); }} onBackToLogin={() => setShowSignup(false)} />;
    }
    return <Login accounts={accounts} onLogin={handleLogin} onShowSignup={() => setShowSignup(true)} />;
  }

  const account = accounts.find(a => a.id === currentAccountId) || accounts[0];

  const navItems = [
    { id: "dashboard", icon: "📊", label: "Dashboard" },
    { id: "calendar", icon: "📅", label: "Calendar" },
    { id: "tasks", icon: "📋", label: "Activities" },
    { id: "members", icon: "👥", label: "Members" },
    { id: "settings", icon: "⚙️", label: "Settings" },
  ];

  const goTab = (id) => { setActiveTab(id); setMobileNavOpen(false); };

  // ── MOBILE LAYOUT ──
  if (isMobile) {
    return (
      <div style={{ minHeight: "100vh", background: "#ffffff", fontFamily: "'Segoe UI', sans-serif", paddingBottom: 64 }}>
        {/* Top Bar */}
        <div style={{
          height: 56, background: "#fdf8f2", borderBottom: "1px solid #f3e6c9",
          display: "flex", alignItems: "center", padding: "0 14px", gap: 10, position: "sticky", top: 0, zIndex: 50
        }}>
          <img src={LOGO_SRC} alt={ORG_NAME_EN} style={{ width: 28, height: 28, borderRadius: "50%", border: "1.5px solid #c8960c", flexShrink: 0 }} />
          <span style={{ color: "#8a1414", fontWeight: 700, fontSize: 15, flex: 1 }}>
            {navItems.find(n => n.id === activeTab)?.label}
          </span>
          <Avatar initials={account.avatar} size={28} />
        </div>

        {/* Page Content */}
        <div style={{ padding: 16 }}>
          {activeTab === "dashboard" && <Dashboard tasks={tasks} onAddTask={saveTask} onDelete={requestDeleteTask} />}
          {activeTab === "calendar" && <CalendarView tasks={tasks} onAddTask={saveTask} onDelete={requestDeleteTask} />}
          {activeTab === "tasks" && <AllTasks tasks={tasks} onSave={saveTask} onDelete={requestDeleteTask} />}
          {activeTab === "members" && <Members members={members} onSave={saveMember} onDelete={requestDeleteMember} />}
          {activeTab === "settings" && (
            <>
              <Settings account={account} accounts={accounts} onUpdateAccount={updateAccount} onAddAdmin={addAdmin} onRemoveAdmin={removeAdmin} onLogout={handleLogout} />
              <button onClick={handleLogout} style={{
                width: "100%", padding: "12px 0", marginTop: 18, background: "#fde8e8",
                border: "1px solid #e08a8a", borderRadius: 8,
                color: "#ef4444", cursor: "pointer", fontSize: 13, fontWeight: 600
              }}>Sign Out</button>
            </>
          )}
        </div>

        {/* Bottom Tab Bar */}
        <div style={{
          position: "fixed", bottom: 0, left: 0, right: 0, height: 64,
          background: "#fdf8f2", borderTop: "1px solid #f3e6c9",
          display: "flex", zIndex: 50, boxShadow: "0 -2px 12px rgba(138,20,20,0.06)"
        }}>
          {navItems.map(item => (
            <button key={item.id} onClick={() => goTab(item.id)} style={{
              flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
              gap: 2, background: "none", border: "none", cursor: "pointer",
              color: activeTab === item.id ? "#8a1414" : "#a98f6f",
              fontWeight: activeTab === item.id ? 700 : 500
            }}>
              <span style={{ fontSize: 19 }}>{item.icon}</span>
              <span style={{ fontSize: 10 }}>{item.label}</span>
            </button>
          ))}
        </div>

        <ConfirmDialog
          open={!!deleteTarget}
          title={deleteTarget?.type === "member" ? "Remove member?" : "Delete activity?"}
          message={deleteTarget ? `This will permanently remove "${deleteTarget.label}". This cannot be undone.` : ""}
          onCancel={() => setDeleteTarget(null)}
          onConfirm={confirmDelete}
        />
      </div>
    );
  }

  // ── DESKTOP / TABLET LAYOUT ──
  return (
    <div style={{ display: "flex", minHeight: "100vh", background: "#ffffff", fontFamily: "'Segoe UI', sans-serif" }}>
      {/* Sidebar */}
      <div style={{
        width: sidebarOpen ? 240 : 64, flexShrink: 0,
        background: "#fdf8f2", borderRight: "1px solid #f3e6c9",
        transition: "width 0.25s", overflow: "hidden", display: "flex", flexDirection: "column"
      }}>
        {/* Sidebar Header */}
        <div style={{ padding: sidebarOpen ? "20px 20px 16px" : "20px 12px 16px", borderBottom: "1px solid #f3e6c9" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <img src={LOGO_SRC} alt={ORG_NAME_EN} style={{ width: 32, height: 32, borderRadius: "50%", flexShrink: 0, border: "1.5px solid #c8960c" }} />
            {sidebarOpen && (
              <div>
                <div style={{ color: "#8a1414", fontWeight: 800, fontSize: 13, lineHeight: 1.2 }}>NJMS</div>
                <div style={{ color: "#7a5a3a", fontSize: 11 }}>Community Manager</div>
              </div>
            )}
          </div>
        </div>

        {/* Nav */}
        <nav style={{ flex: 1, padding: "12px 8px" }}>
          {navItems.map(item => (
            <button key={item.id} onClick={() => setActiveTab(item.id)} style={{
              display: "flex", alignItems: "center", gap: 12, width: "100%",
              padding: sidebarOpen ? "11px 14px" : "11px 0", justifyContent: sidebarOpen ? "flex-start" : "center",
              background: activeTab === item.id ? "linear-gradient(135deg, #f3e6c9, #d9c195)" : "transparent",
              border: "none", borderRadius: 10, cursor: "pointer",
              color: activeTab === item.id ? "#8a1414" : "#7a5a3a",
              fontSize: 14, fontWeight: activeTab === item.id ? 700 : 400,
              marginBottom: 4, transition: "all 0.15s",
              borderLeft: activeTab === item.id ? "3px solid #c8960c" : "3px solid transparent"
            }}>
              <span style={{ fontSize: 18, flexShrink: 0 }}>{item.icon}</span>
              {sidebarOpen && <span>{item.label}</span>}
            </button>
          ))}
        </nav>

        {/* User Info */}
        <div style={{ padding: sidebarOpen ? "14px 16px" : "14px 8px", borderTop: "1px solid #f3e6c9" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: sidebarOpen ? 10 : 0, justifyContent: sidebarOpen ? "flex-start" : "center" }}>
            <Avatar initials={account.avatar} size={32} />
            {sidebarOpen && (
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ color: "#3a1010", fontSize: 12, fontWeight: 600, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{account.name}</div>
                <div style={{ color: "#7a5a3a", fontSize: 11 }}>Admin</div>
              </div>
            )}
          </div>
          {sidebarOpen && (
            <button onClick={handleLogout} style={{
              width: "100%", padding: "8px 0", background: "#fde8e8",
              border: "1px solid #e08a8a", borderRadius: 8,
              color: "#ef4444", cursor: "pointer", fontSize: 12, fontWeight: 600
            }}>Sign Out</button>
          )}
        </div>
      </div>

      {/* Main Content */}
      <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden" }}>
        {/* Top Bar */}
        <div style={{
          height: 60, background: "#fdf8f2", borderBottom: "1px solid #f3e6c9",
          display: "flex", alignItems: "center", padding: "0 20px", gap: 16, flexShrink: 0
        }}>
          <button onClick={() => setSidebarOpen(p => !p)} style={{
            background: "none", border: "1px solid #f3e6c9", borderRadius: 8,
            color: "#7a5a3a", cursor: "pointer", padding: "6px 10px", fontSize: 16
          }}>☰</button>
          <div style={{ flex: 1 }}>
            <span style={{ color: "#8a1414", fontWeight: 700, fontSize: 16 }}>
              {navItems.find(n => n.id === activeTab)?.label}
            </span>
          </div>
          <div style={{ color: "#7a5a3a", fontSize: 12 }}>
            📅 {new Date().toLocaleDateString("en-IN", { weekday: "short", day: "numeric", month: "long", year: "numeric" })}
          </div>
        </div>

        {/* Page Content */}
        <div style={{ flex: 1, overflow: "auto", padding: 24 }}>
          {activeTab === "dashboard" && <Dashboard tasks={tasks} onAddTask={saveTask} onDelete={requestDeleteTask} />}
          {activeTab === "calendar" && <CalendarView tasks={tasks} onAddTask={saveTask} onDelete={requestDeleteTask} />}
          {activeTab === "tasks" && <AllTasks tasks={tasks} onSave={saveTask} onDelete={requestDeleteTask} />}
          {activeTab === "members" && <Members members={members} onSave={saveMember} onDelete={requestDeleteMember} />}
          {activeTab === "settings" && <Settings account={account} accounts={accounts} onUpdateAccount={updateAccount} onAddAdmin={addAdmin} onRemoveAdmin={removeAdmin} onLogout={handleLogout} />}
        </div>
      </div>

      <ConfirmDialog
        open={!!deleteTarget}
        title={deleteTarget?.type === "member" ? "Remove member?" : "Delete activity?"}
        message={deleteTarget ? `This will permanently remove "${deleteTarget.label}". This cannot be undone.` : ""}
        onCancel={() => setDeleteTarget(null)}
        onConfirm={confirmDelete}
      />
    </div>
  );
}
